package compositemldsa_test

import (
	"bytes"
	"encoding/binary"
	"encoding/hex"
	"fmt"
	"slices"
	"testing"

	"github.com/tink-crypto/tink-go/v2/internal/internalapi"
	internalcompmldsa "github.com/tink-crypto/tink-go/v2/internal/signature/compositemldsa"
	compmldsatestvectors "github.com/tink-crypto/tink-go/v2/internal/signature/compositemldsa/testing"

	tinkcompositemldsa "github.com/tink-crypto/tink-go/v2/signature/compositemldsa"
	"github.com/tink-crypto/tink-go/v2/subtle/random"
)

const hexMessage = "54686520717569636b2062726f776e20666f78206a756d7073206f76657220746865206c617a7920646f672e"

const hexMlDsa65Ed25519Signature = ""
const hexMlDsa65EcdsaP256Signature = ""
const hexMlDsa65EcdsaP384Signature = ""
const hexMlDsa65Rsa3072PssSignature = ""
const hexMlDsa65Rsa4096PssSignature = ""
const hexMlDsa65Rsa3072Pkcs1Signature = ""
const hexMlDsa65Rsa4096Pkcs1Signature = ""
const hexMlDsa87EcdsaP384Signature = ""
const hexMlDsa87EcdsaP521Signature = ""
const hexMlDsa87Rsa3072PssSignature = ""
const hexMlDsa87Rsa4096PssSignature = ""

func expectedSignature(classicalAlgorithm tinkcompositemldsa.ClassicalAlgorithm, instance tinkcompositemldsa.MLDSAInstance) []byte {
	var hexSig string
	switch instance {
	case tinkcompositemldsa.MLDSA65:
		switch classicalAlgorithm {
		case tinkcompositemldsa.Ed25519:
			hexSig = hexMlDsa65Ed25519Signature
		case tinkcompositemldsa.ECDSAP256:
			hexSig = hexMlDsa65EcdsaP256Signature
		case tinkcompositemldsa.ECDSAP384:
			hexSig = hexMlDsa65EcdsaP384Signature
		case tinkcompositemldsa.RSA3072PSS:
			hexSig = hexMlDsa65Rsa3072PssSignature
		case tinkcompositemldsa.RSA4096PSS:
			hexSig = hexMlDsa65Rsa4096PssSignature
		case tinkcompositemldsa.RSA3072PKCS1:
			hexSig = hexMlDsa65Rsa3072Pkcs1Signature
		case tinkcompositemldsa.RSA4096PKCS1:
			hexSig = hexMlDsa65Rsa4096Pkcs1Signature
		}
	case tinkcompositemldsa.MLDSA87:
		switch classicalAlgorithm {
		case tinkcompositemldsa.ECDSAP384:
			hexSig = hexMlDsa87EcdsaP384Signature
		case tinkcompositemldsa.ECDSAP521:
			hexSig = hexMlDsa87EcdsaP521Signature
		case tinkcompositemldsa.RSA3072PSS:
			hexSig = hexMlDsa87Rsa3072PssSignature
		case tinkcompositemldsa.RSA4096PSS:
			hexSig = hexMlDsa87Rsa4096PssSignature
		}
	}

	if hexSig == "" {
		panic(fmt.Sprintf("no signature for %v %v", instance, classicalAlgorithm))
	}
	b, err := hex.DecodeString(hexSig)
	if err != nil {
		panic(err)
	}
	return b
}

func TestSignVerifyCorrectnessRandom(t *testing.T) {
	const numRandomSignVerifyIterations = 10
	for _, tc := range compmldsatestvectors.TestCasesSupportedParameters(t) {
		classicalAlgorithm := tinkcompositemldsa.ClassicalAlgorithm(tc.ClassicalAlgorithm)
		instance := tinkcompositemldsa.MLDSAInstance(tc.Instance)
		variant := tinkcompositemldsa.Variant(tc.Variant)
		testName := fmt.Sprintf("%v-%v-%v", classicalAlgorithm, instance, variant)
		t.Run(testName, func(t *testing.T) {
			params, err := tinkcompositemldsa.NewParameters(classicalAlgorithm, instance, variant)
			if err != nil {
				t.Fatalf("NewParameters(%v, %v, %v) err = %v, want nil", classicalAlgorithm, instance, variant, err)
			}
			idReq := uint32(0)
			if variant == tinkcompositemldsa.VariantTink {
				idReq = 0x01020304
			}
			mldsaPrivKey, classicalPrivKey := compmldsatestvectors.CreatePrivateKeyRandom(t, internalcompmldsa.MLDSAInstance(params.MLDSAInstance()), internalcompmldsa.ClassicalAlgorithm(params.ClassicalAlgorithm()))
			compPrivKey, _ := tinkcompositemldsa.NewPrivateKey(mldsaPrivKey, classicalPrivKey, idReq, params)
			pubKey, _ := compPrivKey.PublicKey()
			compPubKey := pubKey.(*tinkcompositemldsa.PublicKey)

			signer, err := tinkcompositemldsa.NewSigner(compPrivKey, internalapi.Token{})
			if err != nil {
				t.Fatalf("NewSigner() err = %v, want nil", err)
			}
			verifier, err := tinkcompositemldsa.NewVerifier(compPubKey, internalapi.Token{})
			if err != nil {
				t.Fatalf("NewVerifier() err = %v, want nil", err)
			}

			for i := 0; i < numRandomSignVerifyIterations; i++ {
				data := random.GetRandomBytes(random.GetRandomUint32()%128 + 1)
				signature, err := signer.Sign(data)
				if err != nil {
					t.Fatalf("Sign(%x) err = %v, want nil", data, err)
				}
				if err := verifier.Verify(signature, data); err != nil {
					t.Errorf("Verify(%x, %x) err = %v, want nil", signature, data, err)
				}
			}
		})
	}
}

func TestSignVerifyCorrectnessDeterministic(t *testing.T) {
	for _, tc := range compmldsatestvectors.TestCasesSupportedParameters(t) {
		classicalAlgorithm := tinkcompositemldsa.ClassicalAlgorithm(tc.ClassicalAlgorithm)
		instance := tinkcompositemldsa.MLDSAInstance(tc.Instance)
		variant := tinkcompositemldsa.Variant(tc.Variant)
		testName := fmt.Sprintf("%v-%v-%v", classicalAlgorithm, instance, variant)
		t.Run(testName, func(t *testing.T) {
			params, err := tinkcompositemldsa.NewParameters(classicalAlgorithm, instance, variant)
			if err != nil {
				t.Fatalf("NewParameters(%v, %v, %v) err = %v, want nil", classicalAlgorithm, instance, variant, err)
			}
			// If the variant is Tink, the signature needs to have a 5-byte prefix
			// (0x01 followed by the 4-byte key ID). The test case verifies that
			// signatures with test vectors are correctly prepended with this prefix.
			idReq := uint32(0)
			if variant == tinkcompositemldsa.VariantTink {
				idReq = 0x01020304
			}
			mldsaPrivKey, classicalPrivKey := compmldsatestvectors.CreatePrivateKeyDeterministic(t, internalcompmldsa.MLDSAInstance(params.MLDSAInstance()), internalcompmldsa.ClassicalAlgorithm(params.ClassicalAlgorithm()))
			compPrivKey, _ := tinkcompositemldsa.NewPrivateKey(mldsaPrivKey, classicalPrivKey, idReq, params)
			expectedSignature := expectedSignature(classicalAlgorithm, instance)

			pubKey, _ := compPrivKey.PublicKey()
			compPubKey := pubKey.(*tinkcompositemldsa.PublicKey)

			signer, err := tinkcompositemldsa.NewSigner(compPrivKey, internalapi.Token{})
			if err != nil {
				t.Fatalf("NewSigner() err = %v, want nil", err)
			}
			verifier, err := tinkcompositemldsa.NewVerifier(compPubKey, internalapi.Token{})
			if err != nil {
				t.Fatalf("NewVerifier() err = %v, want nil", err)
			}

			expectedMessage, err := hex.DecodeString(hexMessage)
			if err != nil {
				t.Fatalf("hex.DecodeString(HexMessage) err = %v", err)
			}
			if variant == tinkcompositemldsa.VariantTink {
				// We append the 5-byte Tink identifier prefix to the raw signature bytes
				// from the test vector so the keyset routing validates correctly.
				prefix := make([]byte, 5)
				prefix[0] = 1
				binary.BigEndian.PutUint32(prefix[1:], idReq)
				expectedSignature = append(prefix, expectedSignature...)
			}

			if err := verifier.Verify(expectedSignature, expectedMessage); err != nil {
				testSig, _ := signer.Sign(expectedMessage)
				if bytes.Equal(testSig, expectedSignature) {
					t.Fatalf("Test signature matches expected signature but verification failed!")
				} else {
					t.Fatalf("Mismatch! len(testSig)=%d len(expected)=%d err=%v\nexpectedSig[:20]=%x\ntestSig[:20]=%x", len(testSig), len(expectedSignature), err, expectedSignature[:20], testSig[:20])
				}
			}

			// Roundtrip deterministic signature test
			data := random.GetRandomBytes(random.GetRandomUint32()%128 + 1)
			signature, err := signer.Sign(data)
			if err != nil {
				t.Fatalf("Sign(%x) err = %v, want nil", data, err)
			}
			if err := verifier.Verify(signature, data); err != nil {
				t.Errorf("Verify(%x, %x) err = %v, want nil", signature, data, err)
			}
		})
	}
}

func TestVerifyFails(t *testing.T) {
	for _, tc := range compmldsatestvectors.TestCasesSupportedParameters(t) {
		classicalAlgorithm := tinkcompositemldsa.ClassicalAlgorithm(tc.ClassicalAlgorithm)
		instance := tinkcompositemldsa.MLDSAInstance(tc.Instance)
		variant := tinkcompositemldsa.Variant(tc.Variant)
		testName := fmt.Sprintf("%v-%v-%v", classicalAlgorithm, instance, variant)
		t.Run(testName, func(t *testing.T) {
			params, err := tinkcompositemldsa.NewParameters(classicalAlgorithm, instance, variant)
			if err != nil {
				t.Fatalf("NewParameters(%v, %v, %v) err = %v, want nil", classicalAlgorithm, instance, variant, err)
			}
			idReq := uint32(0)
			if variant == tinkcompositemldsa.VariantTink {
				idReq = 0x01020304
			}
			mldsaPrivKey, classicalPrivKey := compmldsatestvectors.CreatePrivateKeyDeterministic(t, internalcompmldsa.MLDSAInstance(params.MLDSAInstance()), internalcompmldsa.ClassicalAlgorithm(params.ClassicalAlgorithm()))
			compPrivKey, _ := tinkcompositemldsa.NewPrivateKey(mldsaPrivKey, classicalPrivKey, idReq, params)
			pubKey, _ := compPrivKey.PublicKey()
			compPubKey := pubKey.(*tinkcompositemldsa.PublicKey)

			signer, err := tinkcompositemldsa.NewSigner(compPrivKey, internalapi.Token{})
			if err != nil {
				t.Fatalf("NewSigner() err = %v, want nil", err)
			}
			verifier, err := tinkcompositemldsa.NewVerifier(compPubKey, internalapi.Token{})
			if err != nil {
				t.Fatalf("NewVerifier() err = %v, want nil", err)
			}

			data := random.GetRandomBytes(20)
			signature, err := signer.Sign(data)
			if err != nil {
				t.Fatalf("Sign(%x) err = %v, want nil", data, err)
			}

			// Modify the message.
			if len(data) > 0 {
				modifiedData := slices.Clone(data)
				modifiedData[0] ^= 0x01
				if err := verifier.Verify(signature, modifiedData); err == nil {
					t.Errorf("Verify(signature, %x) err = nil, want error", modifiedData)
				}
			}

			// Message too short.
			if len(data) > 0 {
				shortData := data[:len(data)-1]
				if err := verifier.Verify(signature, shortData); err == nil {
					t.Errorf("Verify(signature, %x) err = nil, want error", shortData)
				}
			}

			// Modify the signature.
			if len(signature) > 0 {
				modifiedSignature := slices.Clone(signature)
				modifiedSignature[len(modifiedSignature)-1] ^= 0x01
				if err := verifier.Verify(modifiedSignature, data); err == nil {
					t.Errorf("Verify(%x, %x) err = nil, want error", modifiedSignature, data)
				}
			}

			// Modify the prefix.
			if variant == tinkcompositemldsa.VariantTink && len(signature) > 4 {
				modifiedSignature := slices.Clone(signature)
				modifiedSignature[0] ^= 0x01
				if err := verifier.Verify(modifiedSignature, data); err == nil {
					t.Errorf("Verify(%x, %x) err = nil, want error", modifiedSignature, data)
				}
			}
		})
	}
}
